var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"흥, 잘도 도망치는군.","JPN":"フン、逃げ足の速いやつらだな。","ENG":"Hmpf, they scurry like rats.","TWN":"哼，逃得真快。"},"stage":{"bg":"BLACK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"어둠 속으로 치고 빠지는 전략인가?","JPN":"闇の中へ身を隠す作戦か？","ENG":"They are using a hit-and-run strategy.","TWN":"現在是要暗著來嗎？"},"stage":{"bg":"BLACK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"괜찮아? 마사키?","JPN":"雅紀、大丈夫？","ENG":"Are you alright, Masaki?","TWN":"你還好嗎？雅紀？"},"stage":{"bg":"BLACK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"난 멀쩡해.","JPN":"ああ、大丈夫だ。","ENG":"I’m fine.","TWN":"我沒事。"},"stage":{"bg":"BLACK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"문제는 저 녀석들도 멀쩡한 것 같다는 거지만.","JPN":"それより、やつらが無傷なことが問題だが。","ENG":"The problem is that they are fine, too.","TWN":"問題是那些傢伙們好像也沒事。"},"stage":{"bg":"BLACK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"움직임이 카운터 같은데…… 대체 왜 이런 곳에 숨어있던 거지?","JPN":"カウンターっぽい動きだったな……\\nどうしてあんなところに隠れていたんだろう？","ENG":"They move like Counters... What were they doing here?","TWN":"看動作似乎是制裁者…爲什麼躲在在這裡？"},"stage":{"bg":"BLACK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그야……","JPN":"それは……","ENG":"Well...","TWN":"這個嘛……"},"stage":{"bg":"BLACK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"붙잡아서 물어보면 알겠지!","JPN":"捕まえて聞けばわかるだろ！","ENG":"We’ll ask them after we catch them!","TWN":"抓來問不就知道囉！"},"stage":{"bg":"BLACK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DARK_NPC_NULL_NULL","text":{"KOREA":"쳇, 무식하게 주먹질은.","JPN":"チッ、力でゴリ押しか。","ENG":"Bear fists? What are you, a brawler?","TWN":"嗟，只懂得揮拳。"},"stage":{"bg":"BLACK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"춤춰라! 연옥!","JPN":"踊れ！　煉獄！","ENG":"Dance of Purgatory!","TWN":"動起來吧，煉獄！"},"stage":{"bg":"BLACK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DARK_NPC_NULL_NULL","text":{"KOREA":"뭣?","JPN":"な、何だ？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"BLACK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DARK_NPC_NULL_NULL","text":{"KOREA":"우아앗! 부, 불이……!","JPN":"うわあっ！　ひ、火が……！","ENG":"Argh! I’m on fire!","TWN":"呃啊啊！火…有火……！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"지금이다, 미나토! 옷에 불이 붙은 녀석을 노려!","JPN":"今だ、湊！　服が燃えてるやつを狙え！","ENG":"Now, Minato! Take out that one with fire!","TWN":"就是現在，南裕夏！鎖定衣服著火的傢伙！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DARK_NPC_NULL_NULL","text":{"KOREA":"크윽!","JPN":"くうっ！","ENG":"Urgh!","TWN":"唔唔！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_CAMP_FIRE_LOOP"},{"id":"L33_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"맞췄어!","JPN":"当たった！","ENG":"I got him!","TWN":"中了！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"좋아, 다음 녀석도……!","JPN":"よし、次のやつも……！","ENG":"Alright, the next one...","TWN":"很好，下一個傢伙也是……！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"큿! 다리가……","JPN":"くっ！　脚が……","ENG":"Argh! My leg!","TWN":"唔！我的腳……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"마사키!","JPN":"雅紀！","ENG":"Masaki!","TWN":"雅紀！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DARK_NPC_NULL_NULL","text":{"KOREA":"기회다! 활 든 녀석을 죽여!","JPN":"今だ！　弓を持ったやつを殺せ！","ENG":"Now! Kill the one with a bow!","TWN":"好機會！殺死那個拿弓的！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"우왓!","JPN":"うわっ！","ENG":"Wah!","TWN":"哎呀！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_02"},{"id":"L48_1","type":"dialog","speaker":"DARK_NPC_NULL_NULL","text":{"KOREA":"……커헉!","JPN":"……カハッ！","ENG":"Aack!","TWN":"……呃呃！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"감히 나나하라 영지에서 이런 짓을 벌이다니, 겁이 없구나.","JPN":"七原家の領地でこのような蛮行を働くとは、恐れを知らぬようだな。","ENG":"You dare violate Nanahara territory? You must have lost your mind.","TWN":"竟敢在七原領地幹這種事，真是膽大包天！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"신분을 밝혀라. 저항하면 벤다.","JPN":"身分を明かせ。さもなければ斬る。","ENG":"Identify yourselves. Or I will cut you down.","TWN":"是誰派你來的！敢反抗就砍掉你的頭！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DARK_NPC_NULL_NULL","text":{"KOREA":"망할…… 뭐야, 이 여자……","JPN":"くそ……なんだ、この女……","ENG":"Darn... What’s up with this woman?","TWN":"該死的……這女的搞什麼……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그 강한 녀석들을…… 전부 쓰러뜨렸어…….","JPN":"あの強いやつらを……全部倒した……","ENG":"They were so strong... Yet you defeated them all...","TWN":"那些很強的傢伙…… 全都被打趴咧……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"덕분에 살았어, 치후유. 너 굉장하구나?","JPN":"おかげで助かったよ、千冬。君すごいんだね！","ENG":"You saved our lives, Chifuyu. You’re amazing.","TWN":"千冬，謝謝你出手相救。你好厲害喔！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"미나토 공이로군요. 여기서 대체 무얼 하고 계시던 겁니까?","JPN":"湊殿でしたか。ここで何をされていたのですか？","ENG":"Mr. Nayuka. What were you doing in this room?","TWN":"原來是你，南裕夏。你在這裡到底在做什麼？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그게…… 안에서 길을 잃는 바람에 말이지.","JPN":"それが……道に迷っちゃって。","ENG":"Um... We kinda lost our way.","TWN":"那個……我們在這裡面迷路了。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"적당한 방을 찾다가 문을 열었더니, 이렇게 되어버렸네. 하하……","JPN":"ちょっと休憩できそうな部屋を適当に探して扉を開けたら、\\nこんなことになっちゃったんだ。ハハ……","ENG":"We were just looking for a room to get some rest... and this happens. Hah hah...","TWN":"想說找個合適的房間，結果一打開門就變成這樣了。 呵呵…"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"적당한 방을 찾은 결과가 이곳이라니. 궁색한 변명처럼 들리는군요.","JPN":"適当な部屋を探して見つけた結果がここですか。\\n苦しい言い訳のようにしか聞こえませんね。","ENG":"You were looking for a room to get some rest? I don’t believe you.","TWN":"找房間找到這裡來？感覺是隨便找個理由搪塞我。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"여긴, 나나하라 당주께서 머무시는 방입니다.","JPN":"ここは、七原家当主が使用している部屋です。","ENG":"This is Lady Nanahara’s room.","TWN":"這裡是七原堂主的寢室。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"……뭐라고?","JPN":"……何だと？","ENG":"What?","TWN":"……什麼？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"잠깐. 그렇다는 건, 저 사람들은 치나츠를 노린 건가?","JPN":"ちょっと待って。ってことは、さっきのやつらは千夏を狙ってたってこと？","ENG":"Wait, that means these assassins were after Chinatsu?","TWN":"等一下，意思是那些人的目標是千夏嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"자객이 더 있을지도 모릅니다.","JPN":"刺客がまだ潜んでいるかもしれません。","ENG":"There might be more.","TWN":"可能還有其他刺客。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"제가 찾아보도록 하지요.","JPN":"私が探してみます。","ENG":"I’ll search for them.","TWN":"我再去巡一巡。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"장로님……?","JPN":"長老……？","ENG":"Elder?","TWN":"長老……？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"아, 치후유.","JPN":"千冬様。","ENG":"Oh, Chifuyu.","TWN":"喔，千冬。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"……그리고 미나토님.","JPN":"……そして湊様。","ENG":"And... Sir Minato.","TWN":"……還有南裕夏。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"흉기를 든 괴한이 본부를 돌아다니고 있기에 제가 처리했습니다.","JPN":"凶器を持った怪しい者がいたので、始末しました。","ENG":"I met a suspicious armed man so I got rid of him.","TWN":"有可疑人士手持武器在總部亂竄，我便將人處理掉了。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"이제 괜찮을 거예요.","JPN":"もう大丈夫なはずです。","ENG":"It will be okay now.","TWN":"現在應該沒事了。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그 자를, 죽이신 겁니까?","JPN":"あの者たちを、始末したのですか？","ENG":"Did you kill the man?","TWN":"長老殺了那傢伙嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"네, 저를 위협하면서 달려들더군요.","JPN":"ええ、私に襲い掛かってきましたので。","ENG":"Yes, he attacked me first.","TWN":"是的，因為他撲過來威脅到我。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그 자가 나나하라 당주님의 방에 숨어 있었습니다.","JPN":"あの者たちは七原家当主の部屋に潜んでいました。","ENG":"That man was hiding in Lady Nanahara’s room.","TWN":"那個人原本躲在七原堂主的房間裡。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"혹시 짚이는 점이 있으신지요?","JPN":"何か思い当たる節はありませんか？","ENG":"Do you know anything about this?","TWN":"長老有想到什麼嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"당주께서는…… 방에 계시지 않았나요?","JPN":"ご当主は……お部屋にいらっしゃらなかったのですか？","ENG":"Lady Nanahara... was not in the room?","TWN":"堂主……不在房間裡嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"예, 다행히.","JPN":"ええ、幸いにも。","ENG":"Yes, fortunately.","TWN":"對，好險！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"여러분? 지금 이곳에서 무슨 일이 벌어진 거죠?","JPN":"皆さん、何の騒ぎですか？","ENG":"What’s going on here?","TWN":"大家怎麼都在這裡？發生什麼事了嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"당주님? 지금까지 어디에 계셨던 건가요?","JPN":"ご当主？　こんな時間までどちらへ？","ENG":"Lady Nanahara? Where have you been?","TWN":"堂主？您剛剛去了哪裡？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그리 멀리 나가진 않았습니다. 사나에 님이 함께 바람을 쐬고 싶다고 하셔서 잠시 바깥에 있었어요.","JPN":"早苗様が風に当たりたいとのことでしたので、しばらく外にいました。\\nここからそう遠くない場所です。","ENG":"I was just in the vicinity. Ms. Hayami wanted to get some fresh air, so I accompanied her.","TWN":"我在附近而已，早苗說想找我一起去吹吹風，所以在外面待了一下。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"……그렇군요. 불행 중 다행인 일입니다.","JPN":"……そうでしたか。ご無事で何よりです。","ENG":"... I see. That was very fortunate.","TWN":"……原來如此，真是不幸中的大幸。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_01"},{"id":"L8_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"방에 계셨다면 화를 입으셨을 테니, 하야미 공에게는 뜻하지 않게 신세를 졌군요.","JPN":"もしお部屋にいらっしゃったなら大変なことになっていたでしょう。\\n速水は図らずも良き判断をしたようですね。","ENG":"Something bad would have happened if you were in the room. It looks like Dame Sanae helped us by chance.","TWN":"要是堂主剛才在房間的話，現在可能已經遭遇不測了，這下欠速水一次人情了呢。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"하지만, 당주님께서 이런 야심한 시각에 호위도 없이 저런 자와 함께 계시는 건 위험합니다.","JPN":"しかし、ご当主が夜分遅くに護衛もつけず、\\nそのような者と一緒に外を出歩くのは危険です。","ENG":"But Lady Nanahara, you can’t associate with someone like her at this hour without your bodyguard.","TWN":"不過這麼晚了，堂主和那種人在一起不帶著護衛是很危險的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"심려 끼쳤다면 죄송합니다. 제가 믿을 수 있는 호위와 반목하게 되는 바람에.","JPN":"ご心配をおかけして申し訳ございません。\\n私が信頼できる護衛と反目することになってしまいましたので。","ENG":"My apologies, but please note that I am currently in a competition with my most trusted bodyguard.","TWN":"抱歉，讓長老擔心。因爲現在和信任的護衛有點反目。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"옷에 피가 묻으셨군요, 사요 장로님.","JPN":"小夜長老、お召し物に血が付いておりますね。","ENG":"I see blood on your clothes, Elder Sayo.","TWN":"小夜長老，您的衣服沾到血了。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"암살자가 당주님을 노리고 이곳에 침입했더군요. 지금 막 한 놈을 처리한 참입니다.","JPN":"暗殺者が数人、ご当主を狙ってここに侵入したのです。\\nそのうちの一人を先ほど始末したところです。","ENG":"It’s from an assassin who came after Lady Nanahara. I just killed one of them.","TWN":"有刺客入侵想要對堂主不利，我才剛把一個傢伙處理掉。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저를 노리는 암살자라고요?","JPN":"私を狙う暗殺者ですか？","ENG":"Assassins, coming after me?","TWN":"有刺客想對我不利？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"대체 왜 그런 일이……?","JPN":"いったいなぜ……？","ENG":"How could it be?","TWN":"怎麼會這樣……？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"이 암살자는 적어도 연합원이 아닙니다. 잔당이 있다면 아직 빠져나가지 못했겠지요.","JPN":"少なくとも暗殺者は連合員ではありません。\\n残党がいるとしたら、まだ逃げられずに隠れているはずです。","ENG":"This assassin is definitely not from our Alliance. I think his accomplices might still be here, if there are any.","TWN":"至少這個刺客不是聯盟的成員，應該還有其他的同夥在附近。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"필시 내부의 사주가 있었을 테니, 사로잡아 심문한다면 진실을 알 수 있을 겁니다.","JPN":"おそらく内通者がいるのでしょうが、捕らえて尋問すればわかることでしょう。","ENG":"I’m sure there’s a betrayer among us who let them in. We have to find them and interrogate them.","TWN":"肯定是有人唆使他們的，只要抓到他們進行審問，就可以知道主謀是誰。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"주모자는 제가 책임을 지고 찾아낼 테니, 당주님과 다른 분들은 이제 염려하지 마시지요.","JPN":"首謀者は私が責任を持って見つけ出します。\\n皆様のご心配には及びません。","ENG":"I will find the betrayer, so don’t worry about it.","TWN":"我會負責找出主謀，堂主和其他人都無須擔心。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"그럼, 평안한 밤 되시길.","JPN":"では、おやすみなさいませ。","ENG":"Have a good night, then.","TWN":"那就祝大家今晚都平安。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"쳇, 평안한 밤은 무슨. 안방에서 자객을 마주쳤는데 퍽이나 잠이 잘 오겠다.","JPN":"チッ、おやすみなさいませだってよ。\\n部屋で命を狙う刺客に遭遇したが、とてもよく寝られそうだな？","ENG":"A good night? How could you have a good night when you found assassins in your room?","TWN":"嗟，平安什麼？在房間裡遇到刺客怎麼可能還睡得著！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"사요 씨는 생각보다 강한 사람이었구나.","JPN":"小夜さんは思ってたより強い人だったんだな。","ENG":"I didn’t know Sayo was so strong.","TWN":"小夜似乎不如外表那樣柔弱呢？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"응? 그게 무슨 소리야?","JPN":"うん？　どういう意味だ？","ENG":"Hm? What do you mean?","TWN":"嗯？那是什麼意思？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"부상을 입은 상태였다곤 해도, 자객을 혼자서 처리하다니 말이야.","JPN":"負傷していたとは言え、刺客を一人で倒しちゃうなんて。","ENG":"Though injured, the assassins were pretty strong. But she handled one by herself.","TWN":"明明受傷了，卻還是可以一個人處理掉刺客。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};